{
  "name": "my-vibe",
  "version": "0.1.0",
  "main": "dist/index.js",
  "types": "dist/index.d.ts",
  "scripts": {
    "build:rust:linux": "cargo build --target aarch64-unknown-linux-gnu --verbose && mv target/aarch64-unknown-linux-gnu/debug/my-vibe target/debug/my-vibe-linux",
    "build:rust:macos": "cargo build --verbose && mv target/debug/my-vibe target/debug/my-vibe-macos",
    "build": "tsc && echo 'Build placeholders completed.'",
    "demo": "node dist/demo.js",
    "start": "node dist/index.js"
  },
  "dependencies": {
    "@mariozechner/pi-coding-agent": "^0.64.0"
  },
  "devDependencies": {
    "typescript": "^5.2.0",
    "@types/node": "^20.5.0"
  }
}

import { execSync } from 'child_process';
import * as path from 'path';

/**
 * Runs the compiled Rust binary and returns its stdout.
 * Dispatches to the appropriate binary for the current platform.
 */
export function helloRust(): string {
  const platform = process.platform;
  let binaryName: string;
  if (platform === 'darwin') {
    binaryName = 'my-vibe';
  } else if (platform === 'linux') {
    binaryName = 'my-vibe-linux';
  } else {
    throw new Error(`Unsupported platform: ${platform}`);
  }

  const binaryPath = path.resolve(__dirname, '../target/debug', binaryName);
  try {
    const output = execSync(binaryPath, { encoding: 'utf-8' });
    return output.trim();
  } catch (err) {
    throw new Error(`Failed to execute Rust binary: ${err}`);
  }
}

import { execSync } from 'child_process';
import * as path from 'path';

/**
 * Executes the Python script and returns its stdout.
 * Placeholder – assumes Python 3 is available as `python3`.
 */
export function helloPython(): string {
  const scriptPath = path.resolve(__dirname, '../src/main.py');
  try {
    const output = execSync(`python3 ${scriptPath}`, { encoding: 'utf-8' });
    return output.trim();
  } catch (err) {
    throw new Error(`Failed to run Python script: ${err}`);
  }
}

import { createAgentSession } from '@mariozechner/pi-coding-agent';

(async () => {
  const { session } = await createAgentSession();

  session.subscribe((event) => {
    if (
      event.type === 'message_update' &&
      event.assistantMessageEvent.type === 'text_delta'
    ) {
      process.stdout.write(event.assistantMessageEvent.delta);
    }
  });

  await session.prompt('What files are in the current directory?');
  session.state.messages.forEach((msg) => {
    console.log(msg);
  });
  console.log();
})();
